1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteStep = { op: "quote"; items: Item[] };
4	type Damage = { itemType: string; amount: number };
5	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer: Customer; steps: Step[] };
8	type QuoteResult = { premium: number };
9	type ClaimResult = { payout: number; remainingCap: number };
10	type StepResult = QuoteResult | ClaimResult;
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE = 0.1;
14	const CURSE_SURCHARGE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT = 0.2;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
20	
21	const BASE_PREMIUM: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const INSURANCE_VALUE: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const DEDUCTIBLE = 100;
40	const CAP_MULTIPLIER = 2;
41	const REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD = 8;
42	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	const BLOCK_SIZE = 3;
46	const BLOCK_PREMIUM = 60;
47	
48	const isBlock = (type: string, count: number): boolean =>
49	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
50	
51	const groupPremium = (type: string, count: number): number =>
52	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
53	
54	const countByType = (items: Item[]): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
57	  return counts;
58	};
59	
60	const sumBasePremiumsByGroup = (items: Item[]): number =>
61	  [...countByType(items)].reduce(
62	    (total, [type, count]) => total + groupPremium(type, count),
63	    0,
64	  );
65	
66	const isCursed = (item: Item): boolean => item.cursed === true;
67	const isHighlyEnchanted = (item: Item): boolean =>
68	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
69	const isLoyalCustomer = (customer: Customer): boolean =>
70	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
71	
72	const surchargeRateFor = (item: Item): number =>
73	  (isCursed(item) ? CURSE_SURCHARGE : 0)
74	  + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
75	
76	const perItemSurcharges = (items: Item[]): number =>
77	  items.reduce(
78	    (total, item) => total + BASE_PREMIUM[item.type] * surchargeRateFor(item),
79	    0,
80	  );
81	
82	const rateIf = (condition: boolean, rate: number): number =>
83	  condition ? rate : 0;
84	
85	const policyWideAdjustments = (
86	  policyBase: number,
87	  customer: Customer,
88	  isFollowUp: boolean,
89	): number => {
90	  const netRate =
91	    FIRST_INSURANCE_SURCHARGE
92	    - rateIf(isLoyalCustomer(customer), LOYALTY_DISCOUNT)
93	    - rateIf(isFollowUp, FOLLOWUP_CONTRACT_DISCOUNT);
94	  return policyBase * netRate;
95	};
96	
97	const quotePremiumFor = (
98	  customer: Customer,
99	  { items }: QuoteStep,
100	  isFollowUp: boolean,
101	): QuoteResult => {
102	  const policyBase = sumBasePremiumsByGroup(items);
103	  const total =
104	    policyBase
105	    + perItemSurcharges(items)
106	    + policyWideAdjustments(policyBase, customer, isFollowUp)
107	    + PROCESSING_FEE;
108	  return { premium: Math.ceil(total) };
109	};
110	
111	type Policy = { items: Item[]; remainingCap: number };
112	
113	const insuranceSumFor = (items: Item[]): number =>
114	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
115	
116	const createPolicy = ({ items }: QuoteStep): Policy => ({
117	  items,
118	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
119	});
120	
121	const reimbursementRateFor = (item: Item): number =>
122	  (item.enchantment ?? 0) >= REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD
123	    ? HIGH_ENCHANTMENT_REIMBURSEMENT
124	    : 1;
125	
126	const findItem = (policy: Policy, itemType: string): Item => {
127	  const item = policy.items.find((i) => i.type === itemType);
128	  if (item === undefined) throw new Error(`Item not in policy: ${itemType}`);
129	  return item;
130	};
131	
132	const payoutForDamage = (policy: Policy, damage: Damage): number => {
133	  const item = findItem(policy, damage.itemType);
134	  const reimbursed = damage.amount * reimbursementRateFor(item);
135	  return Math.max(0, reimbursed - DEDUCTIBLE);
136	};
137	
138	const totalPayout = (policy: Policy, damages: Damage[]): number =>
139	  damages.reduce((sum, d) => sum + payoutForDamage(policy, d), 0);
140	
141	const capAndRoundDown = (amount: number, cap: number): number =>
142	  Math.floor(Math.min(amount, cap));
143	
144	const assertDamagesFitPolicy = (policy: Policy, damages: Damage[]): void => {
145	  const policyCounts = countByType(policy.items);
146	  const damageCounts = new Map<string, number>();
147	  for (const { itemType } of damages) {
148	    damageCounts.set(itemType, (damageCounts.get(itemType) ?? 0) + 1);
149	  }
150	  for (const [itemType, count] of damageCounts) {
151	    if (count > (policyCounts.get(itemType) ?? 0)) {
152	      throw new Error(`More damage entries for ${itemType} than policy covers`);
153	    }
154	  }
155	};
156	
157	const settleClaim = (policy: Policy, { incident }: ClaimStep): ClaimResult => {
158	  assertDamagesFitPolicy(policy, incident.damages);
159	  const uncapped = totalPayout(policy, incident.damages);
160	  const payout = capAndRoundDown(uncapped, policy.remainingCap);
161	  policy.remainingCap -= payout;
162	  return { payout, remainingCap: policy.remainingCap };
163	};
164	
165	export const runScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
166	  const policies: Policy[] = [];
167	  const handle = (step: Step): StepResult => {
168	    if (step.op === "quote") {
169	      const isFollowUp = policies.length > 0;
170	      policies.push(createPolicy(step));
171	      return quotePremiumFor(customer, step, isFollowUp);
172	    }
173	    return settleClaim(policies[step.policy], step);
174	  };
175	  return { results: steps.map(handle) };
176	};
177

